function search(result) {
    var list = [];
    var html = result.html;
    var pattern = /<a class="stui-vodlist__thumb"[^>]*href="([^"]+)"[^>]*title="([^"]+)"[^>]*data-original="([^"]+)"/g;
    var match;
    while ((match = pattern.exec(html)) !== null) {
        var href = match[1];
        var title = match[2];
        var pic = match[3];
        var idMatch = href.match(/\/flim\/(\d+)\//);
        if (idMatch) {
            list.push({
                name: title,
                url: 'https://dongkadi.com/flim/' + idMatch[1] + '/index.html',
                pic: pic
            });
        }
    }
    return JSON.stringify(list);
}

