detail:
function detail(result) {
    var html = result.html;
    var id = result.id;
    var titleMatch = html.match(/<title>([^<]+)<\/title>/);
    var title = titleMatch ? titleMatch[1] : '视频 ' + id;
    var picMatch = html.match(/data-original="([^"]+)"/);
    var pic = picMatch ? picMatch[1] : '';
    var descMatch = html.match(/<span class="detail-sketch"[^>]*>([^<]+)<\/span>/);
    var desc = descMatch ? descMatch[1] : '';
    var playList = [];
    var playPattern = /<a[^>]*href="([^"]+)"[^>]*class="[^"]*btn[^"]*"[^>]*>([^<]+)<\/a>/gi;
    var playMatch;
    while ((playMatch = playPattern.exec(html)) !== null) {
        var href = playMatch[1];
        var name = playMatch[2].trim();
        if (href.includes('flim') || href.includes('player') || href.includes('iframe')) {
            playList.push({
                name: name || '播放',
                url: href.startsWith('http') ? href : 'https://dongkadi.com' + href
            });
        }
    }
    if (playList.length === 0) {
        var iframeMatch = html.match(/<iframe[^>]+src=["']([^"']+)["']/i);
        if (iframeMatch) {
            playList.push({
                name: '播放',
                url: iframeMatch[1]
            });
        }
    }
    var detailResult = {
        name: title,
        pic: pic,
        desc: desc,
        list: playList
    };
    return JSON.stringify(detailResult);
}

play:
function play(result) {
    var html = result.html;
    var url = result.url;
    var videoMatch = html.match(/<video[^>]+src=["']([^"']+)["']/i);
    if (videoMatch) {
        return videoMatch[1];
    }
    var m3u8Match = html.match(/(https?:\/\/[^\s"'<>]+\.m3u8[^\s"'<>]*)/i);
    if (m3u8Match) {
        return m3u8Match[1];
    }
    var iframeMatch = html.match(/<iframe[^>]+src=["']([^"']+)["']/i);
    if (iframeMatch) {
        return '$iframe$' + iframeMatch[1];
    }
    return url;
}
